package Java_Assignment;

public class Assign2_ASCII {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char ch1 = 'A';
        char ch2 = 'a';
        char ch3 = '0';
        char ch4 = '@';

        System.out.println("ASCII value of A = " + (int) ch1);
        System.out.println("ASCII value of a = " + (int) ch2);
        System.out.println("ASCII value of 0 = " + (int) ch3);
        System.out.println("ASCII value of @ = " + (int) ch4);

	}

}
